mapper.select:
select node_id, process_id, node_name, node_order, status, create_by, create_time, update_by, update_time, remark
from approval_node
where node_id = #{nodeId}

mapper.update:
update approval_node
node_name = #{nodeName}, node_order = #{nodeOrder}, status = #{status}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where node_id = #{nodeId}
